using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Set up options with default reflection-based resolver
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed retrieval: GetTypeInfo<T>() returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata for: {personInfo.Type.Name}");
Console.WriteLine($"  Kind: {personInfo.Kind}");

// Serialize using the typed metadata
string json = JsonSerializer.Serialize(new Person("Alice", 30), personInfo);
Console.WriteLine($"  Serialized: {json}");

// 2) Probe without throwing: TryGetTypeInfo returns false if not available
//    First, demonstrate success:
bool found = options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info);
Console.WriteLine($"\nTryGetTypeInfo(Person) => found={found}, type={info?.Type.Name}");

//    Now demonstrate a case where metadata is NOT available.
//    Use a resolver that only handles Person, so querying another type fails gracefully.
var limitedOptions = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver
    {
        Modifiers =
        {
            ti =>
            {
                // Sabotage: return nothing useful for Order
                if (ti.Type == typeof(Order))
                    throw new NotSupportedException();
            }
        }
    }
};

bool foundOrder = limitedOptions.TryGetTypeInfo(typeof(Order), out JsonTypeInfo? orderInfo);
Console.WriteLine($"TryGetTypeInfo(Order) => found={foundOrder}, info is null={orderInfo is null}");

if (!foundOrder)
    Console.WriteLine("  → Gracefully handled missing metadata (no exception thrown).");

// Types used in the demo
public record Person(string Name, int Age);
public record Order(int Id, decimal Total);
EOF
